// Calculate revenue metrics
const orders = $input.all()[0]?.json || [];
const adData = $input.all()[1]?.json || { data: [] };

const yesterday = DateTime.now().minus({ days: 1 });

// Revenue calculations
const totalRevenue = orders.reduce((sum, o) => sum + parseFloat(o.total_price || 0), 0);
const totalOrders = orders.length;
const aov = totalOrders > 0 ? totalRevenue / totalOrders : 0;
const refunds = orders.filter(o => o.financial_status === 'refunded').length;
const refundAmount = orders
  .filter(o => o.financial_status === 'refunded')
  .reduce((sum, o) => sum + parseFloat(o.total_price || 0), 0);

// Ad spend calculations
const adSpend = adData.data?.reduce((sum, a) => sum + parseFloat(a.spend || 0), 0) || 0;
const roas = adSpend > 0 ? (totalRevenue / adSpend).toFixed(2) : 0;

// Previous day comparison (mock data - replace with actual fetch)
const prevDayRevenue = totalRevenue * 0.95; // Placeholder
const revenueChange = ((totalRevenue - prevDayRevenue) / prevDayRevenue * 100).toFixed(1);

return [{
  json: {
    date: yesterday.toFormat('yyyy-MM-dd'),
    revenue: totalRevenue.toFixed(2),
    orders: totalOrders,
    aov: aov.toFixed(2),
    refunds: refunds,
    refund_amount: refundAmount.toFixed(2),
    ad_spend: adSpend.toFixed(2),
    roas: roas,
    revenue_change: revenueChange,
    gross_margin: ((totalRevenue - adSpend) / totalRevenue * 100).toFixed(1),
    generated_at: new Date().toISOString()
  }
}];

