// Check for anomalies
const data = $input.all()[0].json;
const analysis = $input.all()[1].json.content;

const anomalies = [];

if (parseFloat(data.roas) < 2.0) {
  anomalies.push(`ROAS dropped to ${data.roas}x`);
}
if (parseFloat(data.revenue_change) < -20) {
  anomalies.push(`Revenue down ${data.revenue_change}%`);
}
if (parseFloat(data.gross_margin) < 30) {
  anomalies.push(`Margin at ${data.gross_margin}%`);
}

return [{
  json: {
    ...data,
    analysis: analysis,
    has_anomalies: anomalies.length > 0,
    anomalies: anomalies,
    alert_level: anomalies.length > 2 ? 'critical' : anomalies.length > 0 ? 'warning' : 'normal'
  }
}];

